package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.validation.*;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.util.*;public class BedServiceImpl implements BedService{private final BedDao dao;private final BedValidator validator;private final AuditLogDao audit;public BedServiceImpl(){this(new BedDaoImpl(),new BedValidator(),new AuditLogDaoImpl());}public BedServiceImpl(BedDao d,BedValidator v,AuditLogDao a){dao=d;validator=v;audit=a;}public Page<Bed>listBeds(PageRequest p,Long r,String s){try{return dao.findAll(p,r,s);}catch(Exception e){return new Page<>(List.of(),p.getPageNumber(),p.getPageSize(),0);}}public Optional<Bed>getBed(Long id){try{return dao.findById(id);}catch(Exception e){return Optional.empty();}}public List<Bed>getAvailableBeds(Long d,String t){try{return dao.findAvailableBeds(d,t);}catch(Exception e){return List.of();}}public ServiceResult<Long>createBed(BedForm f,AuditContext a){ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{Bed b=from(f);if("OCCUPIED".equals(b.getStatus()))return failL(ServiceResult.Status.CONFLICT,"Occupancy is managed by admissions");if(dao.existsByRoomAndBedNumber(b.getRoomId(),b.getBedNumber()))return failL(ServiceResult.Status.DUPLICATE,"Bed number already exists in this room");long id=dao.create(b);event("BED_CREATED",id,a);return ServiceResult.success("Bed created",id);}catch(Exception e){return failL(ServiceResult.Status.SYSTEM_ERROR,"Bed service unavailable");}}public ServiceResult<Void>updateBed(BedForm f,AuditContext a){ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{Bed old=dao.findById(f.getBedId()).orElse(null);if(old==null)return fail(ServiceResult.Status.NOT_FOUND,"Bed not found");if("OCCUPIED".equals(old.getStatus())||"OCCUPIED".equals(f.getStatus()))return fail(ServiceResult.Status.CONFLICT,"Occupied beds are managed by admissions");Bed b=from(f);b.setBedId(f.getBedId());if(dao.existsByRoomAndBedNumberExcludingId(b.getRoomId(),b.getBedNumber(),b.getBedId()))return fail(ServiceResult.Status.DUPLICATE,"Bed number already exists");dao.update(b);event("BED_UPDATED",b.getBedId(),a);return ServiceResult.success("Bed updated",null);}catch(Exception e){return fail(ServiceResult.Status.SYSTEM_ERROR,"Bed service unavailable");}}public ServiceResult<Void>updateBedStatus(Long id,String action,AuditContext a){String st=Map.of("available","AVAILABLE","maintenance","MAINTENANCE","deactivate","INACTIVE").get(action);if(st==null)return fail(ServiceResult.Status.VALIDATION_ERROR,"Invalid action");try(Connection c=DatabaseConnectionManager.getConnection()){c.setAutoCommit(false);try{Bed b=dao.lockById(c,id).orElse(null);if(b==null)return fail(ServiceResult.Status.NOT_FOUND,"Bed not found");if("OCCUPIED".equals(b.getStatus())){event("BED_STATUS_CHANGE_BLOCKED",id,a);return fail(ServiceResult.Status.CONFLICT,"Occupied bed cannot be changed");}dao.updateStatus(c,id,st);c.commit();event("BED_STATUS_CHANGED",id,a);return ServiceResult.success("Bed status updated",null);}catch(Exception e){c.rollback();throw e;}}catch(Exception e){return fail(ServiceResult.Status.SYSTEM_ERROR,"Bed service unavailable");}}private Bed from(BedForm f){Bed b=new Bed();b.setRoomId(f.getRoomId());b.setBedNumber(f.getBedNumber().trim().toUpperCase());b.setStatus(f.getStatus().toUpperCase());return b;}private void event(String e,Long id,AuditContext a){try{audit.recordEvent(e,a==null?null:a.userId(),"BED",id,a==null?null:a.ipAddress(),a==null?null:a.userAgent());}catch(Exception ignored){}}private ServiceResult<Void>fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Long>failL(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}}
